     1→#!/usr/bin/env node
     2→/**
     3→ * SessionStart Hook - Load previous context on new session
     4→ *
     5→ * Cross-platform (Windows, macOS, Linux)
     6→ *
     7→ * Runs when a new Claude session starts. Checks for recent session
     8→ * files and notifies Claude of available context to load.
     9→ */
    10→
    11→const {
    12→  getSessionsDir,
    13→  getLearnedSkillsDir,
    14→  findFiles,
    15→  ensureDir,
    16→  log
    17→} = require('../lib/utils');
    18→const { getPackageManager, getSelectionPrompt } = require('../lib/package-manager');
    19→const { listAliases } = require('../lib/session-aliases');
    20→
    21→async function main() {
    22→  const sessionsDir = getSessionsDir();
    23→  const learnedDir = getLearnedSkillsDir();
    24→
    25→  // Ensure directories exist
    26→  ensureDir(sessionsDir);
    27→  ensureDir(learnedDir);
    28→
    29→  // Check for recent session files (last 7 days)
    30→  // Match both old format (YYYY-MM-DD-session.tmp) and new format (YYYY-MM-DD-shortid-session.tmp)
    31→  const recentSessions = findFiles(sessionsDir, '*-session.tmp', { maxAge: 7 });
    32→
    33→  if (recentSessions.length > 0) {
    34→    const latest = recentSessions[0];
    35→    log(`[SessionStart] Found ${recentSessions.length} recent session(s)`);
    36→    log(`[SessionStart] Latest: ${latest.path}`);
    37→  }
    38→
    39→  // Check for learned skills
    40→  const learnedSkills = findFiles(learnedDir, '*.md');
    41→
    42→  if (learnedSkills.length > 0) {
    43→    log(`[SessionStart] ${learnedSkills.length} learned skill(s) available in ${learnedDir}`);
    44→  }
    45→
    46→  // Check for available session aliases
    47→  const aliases = listAliases({ limit: 5 });
    48→
    49→  if (aliases.length > 0) {
    50→    const aliasNames = aliases.map(a => a.name).join(', ');
    51→    log(`[SessionStart] ${aliases.length} session alias(es) available: ${aliasNames}`);
    52→    log(`[SessionStart] Use /sessions load <alias> to continue a previous session`);
    53→  }
    54→
