     1→#!/usr/bin/env node
     2→/**
     3→ * Strategic Compact Suggester
     4→ *
     5→ * Cross-platform (Windows, macOS, Linux)
     6→ *
     7→ * Runs on PreToolUse or periodically to suggest manual compaction at logical intervals
     8→ *
     9→ * Why manual over auto-compact:
    10→ * - Auto-compact happens at arbitrary points, often mid-task
    11→ * - Strategic compacting preserves context through logical phases
    12→ * - Compact after exploration, before execution
    13→ * - Compact after completing a milestone, before starting next
    14→ */
    15→
    16→const path = require('path');
    17→const {
    18→  getTempDir,
    19→  readFile,
    20→  writeFile,
    21→  log
    22→} = require('../lib/utils');
    23→
    24→async function main() {
    25→  // Track tool call count (increment in a temp file)
    26→  // Use a session-specific counter file based on PID from parent process
    27→  // or session ID from environment
    28→  const sessionId = process.env.CLAUDE_SESSION_ID || process.ppid || 'default';
    29→  const counterFile = path.join(getTempDir(), `claude-tool-count-${sessionId}`);
    30→  const threshold = parseInt(process.env.COMPACT_THRESHOLD || '50', 10);
    31→
    32→  let count = 1;
    33→
    34→  // Read existing count or start at 1
    35→  const existing = readFile(counterFile);
    36→  if (existing) {
    37→    count = parseInt(existing.trim(), 10) + 1;
    38→  }
    39→
    40→  // Save updated count
    41→  writeFile(counterFile, String(count));
    42→
    43→  // Suggest compact after threshold tool calls
    44→  if (count === threshold) {
    45→    log(`[StrategicCompact] ${threshold} tool calls reached - consider /compact if transitioning phases`);
    46→  }
    47→
    48→  // Suggest at regular intervals after threshold
    49→  if (count > threshold && count % 25 === 0) {
    50→    log(`[StrategicCompact] ${count} tool calls - good checkpoint for /compact if context is stale`);
    51→  }
    52→
    53→  process.exit(0);
    54→}
    55→
    56→main().catch(err => {
    57→  console.error('[StrategicCompact] Error:', err.message);
    58→  process.exit(0);
    59→});
