     1→#!/usr/bin/env node
     2→/**
     3→ * Continuous Learning - Session Evaluator
     4→ *
     5→ * Cross-platform (Windows, macOS, Linux)
     6→ *
     7→ * Runs on Stop hook to extract reusable patterns from Claude Code sessions
     8→ *
     9→ * Why Stop hook instead of UserPromptSubmit:
    10→ * - Stop runs once at session end (lightweight)
    11→ * - UserPromptSubmit runs every message (heavy, adds latency)
    12→ */
    13→
    14→const path = require('path');
    15→const fs = require('fs');
    16→const {
    17→  getLearnedSkillsDir,
    18→  ensureDir,
    19→  readFile,
    20→  countInFile,
    21→  log
    22→} = require('../lib/utils');
    23→
    24→async function main() {
    25→  // Get script directory to find config
    26→  const scriptDir = __dirname;
    27→  const configFile = path.join(scriptDir, '..', '..', 'skills', 'continuous-learning', 'config.json');
    28→
    29→  // Default configuration
    30→  let minSessionLength = 10;
    31→  let learnedSkillsPath = getLearnedSkillsDir();
    32→
    33→  // Load config if exists
    34→  const configContent = readFile(configFile);
    35→  if (configContent) {
    36→    try {
    37→      const config = JSON.parse(configContent);
    38→      minSessionLength = config.min_session_length || 10;
    39→
    40→      if (config.learned_skills_path) {
    41→        // Handle ~ in path
    42→        learnedSkillsPath = config.learned_skills_path.replace(/^~/, require('os').homedir());
    43→      }
    44→    } catch {
    45→      // Invalid config, use defaults
    46→    }
    47→  }
    48→
    49→  // Ensure learned skills directory exists
    50→  ensureDir(learnedSkillsPath);
    51→
    52→  // Get transcript path from environment (set by Claude Code)
    53→  const transcriptPath = process.env.CLAUDE_TRANSCRIPT_PATH;
    54→
    55→  if (!transcriptPath || !fs.existsSync(transcriptPath)) {
    56→    process.exit(0);
    57→  }
    58→
    59→  // Count user messages in session
    60→  const messageCount = countInFile(transcriptPath, /"type":"user"/g);
    61→
    62→  // Skip short sessions
    63→  if (messageCount < minSessionLength) {
    64→    log(`[ContinuousLearning] Session too short (${messageCount} messages), skipping`);
    65→    process.exit(0);
    66→  }
    67→
    68→  // Signal to Claude that session should be evaluated for extractable patterns
    69→  log(`[ContinuousLearning] Session has ${messageCount} messages - evaluate for extractable patterns`);
    70→  log(`[ContinuousLearning] Save learned skills to: ${learnedSkillsPath}`);
    71→
    72→  process.exit(0);
    73→}
    74→
    75→main().catch(err => {
    76→  console.error('[ContinuousLearning] Error:', err.message);
    77→  process.exit(0);
    78→});
